insert into public.organizations (name, slug) values ('MatriX Demo Organization', 'matrix-demo') on conflict (slug) do nothing;
insert into public.roles (name, description) values
 ('Organization Admin','Full organization access'),('Construction Manager','Construction approvals and project controls'),('Site Engineer','Site material requests and progress'),('Warehouse Manager','Receiving, issue, transfer and counts'),('Procurement Officer','Suppliers, requisitions and purchase orders'),('Industrial Production Manager','Production planning and manufacturing orders'),('Factory Operator','Production execution'),('Finance','Costs and supplier payment status'),('Quality Inspector','Quality decisions and holds'),('Safety Officer','Safety inspections and incidents'),('Client','Read-only project visibility'),('Vendor','Scoped supplier portal') on conflict (name) do nothing;
insert into public.permissions (key, description) values
 ('projects.read','View projects'),('projects.write','Manage projects'),('material_requests.read','View material requests'),('material_requests.approve','Approve material requests'),('inventory.read','View inventory'),('inventory.post','Post inventory movements'),('waste.write','Capture and approve waste'),('procurement.write','Manage procurement'),('production.write','Manage production'),('reports.export','Export reports'),('settings.write','Manage organization settings') on conflict (key) do nothing;
insert into public.plans (code, name, monthly_price) values ('base','Base',7500),('base_plus','Base+',18000),('pro','Pro',38000),('max','Max',0) on conflict (code) do nothing;
insert into public.plan_features(plan_id, feature_key, enabled, numeric_limit) select p.id, f.key, f.enabled, f.limit from public.plans p cross join (values ('procurement',true,100),('waste',true,500),('industrial',true,100),('analytics',true,1000),('ai_forecasting',true,100),('audit_export',true,100)) f(key,enabled,limit) where p.code in ('pro','max') on conflict do nothing;
